class Solution {
public:
    int numWays(int steps, int arrLen) {
        long long dp[steps + 1][arrLen + 1];
        memset(dp, 0, sizeof(dp));
        dp[0][0] = 1;
        for (int i = 1; i <= steps; i++) {
            for (int j = 0; j < arrLen; j++) {
                dp[i][j] = (dp[i - 1][j] + dp[i - 1][(j + 1) % arrLen] + dp[i - 1][(j - 1 + arrLen) % arrLen]) % 1000000007;
            }
        }
        return dp[steps][0];
    }
};
